from sbxcpp.space import Space, Tilemap, BodyID
from vmath import vec3, vec3i
from random import Random
from godot import load, Callable
from godot.classes import GDScript

BASE_TILE = 1
WALL_TILE = 2

class Playground:
    def on_pair_add(self, a: BodyID, b: BodyID, xzl: vec3i, normal: vec3):
        print(f"on_pair_add: a={a}, b={b}, xzl={xzl}, normal={normal}")
    def on_pair_remove(self, a: BodyID, b: BodyID, xzl: vec3i):
        print(f"on_pair_remove: a={a}, b={b}, xzl={xzl}")

    def __init__(self):
        tilemap = Tilemap(20, 20)
        self.space = Space(tilemap, 10, self)
    
        rnd = Random(17)
        # generate
        for x in range(tilemap.width):
            for y in range(tilemap.height):
                tilemap.set(x, y, 0, BASE_TILE)
                if rnd.random() < 0.1:
                    tilemap.set(x, y, 1, WALL_TILE)
        
        self.hero = self.space.create_body(3, vec3.ONE * 0.5, 0)
        self.space.teleport_body(self.hero, vec3(0.5, 0.5, 0.5))
        print(self.space.body_get_position(self.hero))
        print(self.space.body_get_chunk_index(self.hero))

        tile_body = self.space.create_body(0, vec3.ONE * 0.5, 0)
        self.space.teleport_body(tile_body, vec3(0, -0.5, 0))
        self.space.register_tile_body(BASE_TILE, tile_body)

        tile_body = self.space.create_body(0, vec3.ONE * 0.5, 1)
        self.space.teleport_body(tile_body, vec3(0, 0.5, 0))
        self.space.register_tile_body(WALL_TILE, tile_body)

    def move_hero_and_step(self, vel_x: float, vel_z: float, delta: float):
        pos = self.space.body_get_position(self.hero)
        self.space.body_set_velocity(self.hero, vec3(vel_x, 0, vel_z))
        self.space.step(delta)
        return pos
    

instance = Playground()
